# Manticore can't sort by `text` fields, so we have to create a duplicate `ArtistNameSort` field so we can sort by that value.
create table artworks (id bigint, Name text, UrlName text, ArtistName text, ArtistNameSort string, ArtistUrlName text, ArtistAlternateNames text, Exception text, Notes text, EbookTitle text, EbookAuthors text, Tags text, Status string, SubmitterUserId int, CompletedYear int, EbookId bigint, Created timestamp) morphology = 'lemmatize_en' index_exact_words = '1';
